import java.io.File;
import java.io.FileWriter;
import java.io.IOException;

import org.owasp.encoder.Encode;

public class XSSFixedCode {
    public static void main(String[] args) throws IOException {
        // Simulating user input from a form submission
        String userInput = "<script>alert('XSS Vulnerability')</script>";

        // Properly handling user input by encoding it before outputting it to an HTML page
        File file = new File("output.html");
        FileWriter writer = new FileWriter(file);
        writer.write("<html>");
        writer.write("<head><title>XSS Vulnerability Demo</title></head>");
        writer.write("<body>");
        writer.write("<h1>Welcome, " + Encode.forHtml(userInput) + "</h1>"); // User input is properly encoded for HTML context
        writer.write("</body>");
        writer.write("</html>");

        writer.close();
    }
}

### Explanation:
취약유형: Cross-Site Scripting (XSS)
